/// Phase 0 smoke test: importable from JS, returns a constant string.
/// Real entity-decoder surface lands in later phases.
#[napi]
pub fn ping() -> &'static str {
	"pong"
}

/// Phase 1 parity probe — decode a captured `CSVCMsg_FlattenedSerializer`
/// blob with prost and return structural counts. The JS test compares these
/// against the ts-proto decode of the same bytes.
#[napi(object)]
pub struct FlattenedSerializerSummary {
	pub symbols: u32,
	pub fields: u32,
	pub serializers: u32,
}

#[napi]
pub fn decode_flattened_serializer_summary(bytes: &[u8]) -> Result<FlattenedSerializerSummary, Error> {
	let msg = proto::CsvcMsgFlattenedSerializer::decode(bytes)
		.map_err(|e| Error::from_reason(format!("prost decode failed: {e}")))?;
	Ok(FlattenedSerializerSummary {
		symbols: msg.symbols.len() as u32,
		fields: msg.fields.len() as u32,
		serializers: msg.serializers.len() as u32,
	})
}

