	/// Uint8Array. The production decoder never crosses the FFI boundary for
	/// per-field byte reads (those happen inside Rust), so this allocation-on-
	/// every-call shape is fine — it only exists for the Phase 2 parity test.
	#[napi]
	pub fn read_bytes(&mut self, len: u32) -> Vec<u8> {
		let mut out = vec![0u8; len as usize];
		self.inner.read_bytes_into(&mut out);
		out
	}

	#[napi]
	pub fn read_bytes_to_slice(&mut self, size: u32) -> Vec<u8> {
		let mut out = vec![0u8; size as usize];
		self.inner.read_bytes_into(&mut out);
		out
	}

